            decisions: Vec::new(),
            open_hypotheses: Vec::new(),
            operational_scars: vec![EvidenceNote {
                text: "naive probe caused data loss".into(),
                evidence: envelope
                    .surfaced
                    .iter()
                    .filter(|s| s.label.starts_with('s'))
                    .map(|s| s.label.clone())
                    .take(1)
                    .collect(),
            }],
            avoid_repeating: Vec::new(),
            next_step: crate::adapters::ActionNote {
                text: "run benchmark adapter".into(),
                evidence: Vec::new(),
            },
        };

        // Evaluate both arms against real ground truth
        let control_eval = evaluate_output(&control_output, &scenario.truth, &envelope);
        let treatment_eval = evaluate_output(&treatment_output, &scenario.truth, &envelope);
        let control_survival =
            benchmark_survival_analysis(&control_output, &scenario.truth, &envelope);
        let treatment_survival =
            benchmark_survival_analysis(&treatment_output, &scenario.truth, &envelope);

        // Treatment should score better (more items matched)
        assert!(
            treatment_eval.resume_accuracy_score >= control_eval.resume_accuracy_score,
            "treatment ({}) should score >= control ({})",
            treatment_eval.resume_accuracy_score,
            control_eval.resume_accuracy_score
        );

        // Build Phase3ClassResult from real data
        let class_result = Phase3ClassResult {
            class: BenchmarkClass::AgentSwapSurvival,
            control_survival: Some(control_survival),
            treatment_survival: Some(treatment_survival),
            hypotheses: vec![SurvivalHypothesis {
                feature_name: "file_path".into(),
                category: "CriticalFact".into(),
                direction: "SurvivedMore".into(),
                hint: "Prefer items with file paths".into(),
            }],
            delta_ras: treatment_eval.resume_accuracy_score - control_eval.resume_accuracy_score,
            delta_cfsr: treatment_eval.critical_fact_survival_rate
                - control_eval.critical_fact_survival_rate,
            delta_csr: treatment_eval.constraint_survival_rate
                - control_eval.constraint_survival_rate,
            delta_osr: treatment_eval.operational_scar_retention
                - control_eval.operational_scar_retention,
        };

        // Duplicate across 3 classes to meet minimum threshold
        let class_results = vec![class_result.clone(), class_result.clone(), class_result];
        let hypotheses = vec![SurvivalHypothesis {
            feature_name: "file_path".into(),
            category: "CriticalFact".into(),
            direction: "SurvivedMore".into(),
            hint: "Prefer items with file paths".into(),
        }];

        let phase3_report = generate_phase3_report(&class_results, &hypotheses, 1);
        assert!(
            phase3_report.hypotheses_tested > 0,
            "must test at least one hypothesis"
        );

        // Write outcomes to real kernel
        let written = write_phase3_outcomes_to_kernel(&kernel, &context.id, &phase3_report);
        assert!(
            written.is_ok(),
            "kernel write must succeed: {:?}",
            written.err()
        );

        // Verify the full report serializes
        let json = serde_json::to_string_pretty(&phase3_report).unwrap();
        assert!(json.contains("hypotheses_tested"));
        assert!(json.contains("cycle"));
    }
}

use std::env;
use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use serde::Serialize;
use serde_json::{Value, json};

pub const DEFAULT_CLAUDE_SERVER_NAME: &str = "ice-shared-continuity-kernel";
pub const DEFAULT_CLAUDE_MACHINE_ROOT_DIR: &str = ".claude/organisms/ice";

const ICE_VERSION: &str = env!("CARGO_PKG_VERSION");

#[derive(Debug, Clone)]
pub struct ClaudeCodeInstallRequest {
    pub organism_root: Option<PathBuf>,
    pub server_name: String,
    pub code_config_path: Option<PathBuf>,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ClaudeCodeInstallResult {
    pub changed: bool,
    pub code_config_path: String,
    pub organism_root: String,
    pub server_name: String,
    pub command: String,
    pub args: Vec<String>,
    pub restart_required: bool,
    pub skipped_malformed: bool,
}

#[derive(Debug, Clone)]
pub struct ClaudeCodeUninstallRequest {
    pub server_name: String,
    pub code_config_path: Option<PathBuf>,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ClaudeCodeUninstallResult {
    pub changed: bool,
    pub code_config_path: String,
    pub skipped_malformed: bool,
}

#[derive(Debug, Clone)]
pub struct ClaudeCodeStatusRequest {
    pub server_name: String,
    pub code_config_path: Option<PathBuf>,
    pub organism_root: Option<PathBuf>,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ClaudeCodeStatusResult {
    pub binary_path: String,
    pub binary_exists: bool,
    pub organism_root: String,
    pub organism_root_exists: bool,
    pub code_config_path: String,
    pub code_config_found: bool,
    pub code_has_ice_entry: bool,
    pub ice_version: String,
}

pub fn install_claude_code(request: ClaudeCodeInstallRequest) -> Result<ClaudeCodeInstallResult> {
    validate_server_name(&request.server_name)?;

    let binary = resolve_binary()?;
    let organism_root = resolve_organism_root(request.organism_root.as_ref())?;
    let code_config_path = resolve_code_config(request.code_config_path.as_deref())?;

    fs::create_dir_all(&organism_root)
        .with_context(|| format!("creating organism root {}", organism_root.display()))?;

    let args = vec![
        "--root".to_string(),
        organism_root.display().to_string(),
        "mcp".to_string(),
    ];
    let entry = build_server_entry(&binary, &args);
    let (changed, skipped_malformed) =
        upsert_code_entry(&code_config_path, &request.server_name, &entry)?;

    Ok(ClaudeCodeInstallResult {
        changed,
        code_config_path: code_config_path.display().to_string(),
        organism_root: organism_root.display().to_string(),
        server_name: request.server_name,
        command: binary.display().to_string(),
        args,
        restart_required: true,
        skipped_malformed,
    })
}

pub fn uninstall_claude_code(
    request: ClaudeCodeUninstallRequest,
) -> Result<ClaudeCodeUninstallResult> {
    validate_server_name(&request.server_name)?;

    let code_config_path = resolve_code_config(request.code_config_path.as_deref())?;
    let (changed, skipped_malformed) =
        remove_managed_entry(&code_config_path, &request.server_name)?;

    Ok(ClaudeCodeUninstallResult {
        changed,
        code_config_path: code_config_path.display().to_string(),
        skipped_malformed,
    })
}

pub fn claude_code_status(request: ClaudeCodeStatusRequest) -> Result<ClaudeCodeStatusResult> {
    validate_server_name(&request.server_name)?;

    let binary = resolve_binary()?;
    let organism_root = resolve_organism_root(request.organism_root.as_ref())?;
    let code_config_path = resolve_code_config(request.code_config_path.as_deref())?;

    Ok(ClaudeCodeStatusResult {
        binary_path: binary.display().to_string(),
        binary_exists: binary.exists(),
        organism_root: organism_root.display().to_string(),
        organism_root_exists: organism_root.exists(),
        code_config_path: code_config_path.display().to_string(),
        code_config_found: code_config_path.exists(),
        code_has_ice_entry: has_ice_entry(&code_config_path, &request.server_name),
        ice_version: ICE_VERSION.to_string(),
    })
}

fn resolve_binary() -> Result<PathBuf> {
    env::current_exe().context("resolving current executable path")
}

fn resolve_home() -> Result<PathBuf> {
    #[cfg(windows)]
    if let Some(val) = env::var_os("USERPROFILE") {
        return Ok(PathBuf::from(val));
    }
    if let Some(val) = env::var_os("HOME") {
        return Ok(PathBuf::from(val));
    }
    anyhow::bail!("HOME environment variable not set; cannot resolve Claude Code paths")
}

fn resolve_absolute(path: impl AsRef<Path>) -> Result<PathBuf> {
    let path = path.as_ref();
    if path.is_absolute() {
        return Ok(path.to_path_buf());
    }
    Ok(env::current_dir()
        .context("resolving current working directory")?
        .join(path))
}

fn resolve_organism_root(requested: Option<&PathBuf>) -> Result<PathBuf> {
    if let Some(path) = requested {
        return resolve_absolute(path);
    }
    let home = resolve_home()?;
    Ok(home.join(DEFAULT_CLAUDE_MACHINE_ROOT_DIR))
}

fn resolve_code_config(override_path: Option<&Path>) -> Result<PathBuf> {
    if let Some(path) = override_path {
        return resolve_absolute(path);
    }
    let home = resolve_home()?;
    Ok(home.join(".claude.json"))
}

fn validate_server_name(server_name: &str) -> Result<()> {
    if server_name.is_empty()
        || !server_name
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '-')
    {
        anyhow::bail!(
            "server name must contain only ASCII letters, digits, underscores, or hyphens"
        );
    }
    Ok(())
}

fn build_server_entry(command: &Path, args: &[String]) -> Value {
    json!({
        "type": "stdio",
        "command": command.display().to_string(),
        "args": args,
        "env": {},
        "_ice_managed": true,
        "_ice_version": ICE_VERSION,
    })
}

fn read_config(path: &Path) -> (Value, bool) {
    if !path.exists() {
        return (json!({}), false);
    }
    let text = match fs::read_to_string(path) {
        Ok(text) => text,
        Err(err) => {
            eprintln!(
                "warning: could not read {}: {err}; skipping",
                path.display()
            );
            return (json!({}), true);
        }
    };
    match serde_json::from_str::<Value>(&text) {
        Ok(value) if value.is_object() => (value, false),
        _ => {
            eprintln!(
                "warning: {} contains malformed or non-object JSON; skipping",
                path.display()
            );
            (json!({}), true)
        }
    }
}

fn write_config(path: &Path, value: &Value) -> Result<()> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)
            .with_context(|| format!("creating config directory {}", parent.display()))?;
    }
    let rendered = serde_json::to_string_pretty(value).context("rendering Claude config JSON")?;
    fs::write(path, rendered).with_context(|| format!("writing Claude config {}", path.display()))
}

fn upsert_code_entry(config_path: &Path, server_name: &str, entry: &Value) -> Result<(bool, bool)> {
    let (mut config, malformed) = read_config(config_path);
    if malformed {
        return Ok((false, true));
    }

    let servers = config
        .as_object_mut()
        .expect("config must be object")
        .entry("mcpServers")
        .or_insert_with(|| json!({}));
    let servers_obj = servers
        .as_object_mut()
        .context("Claude Code config `mcpServers` is not a JSON object")?;

    if let Some(existing) = servers_obj.get(server_name) {
        let managed = existing
            .get("_ice_managed")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        if !managed {
            anyhow::bail!(
                "Claude Code config already contains unmanaged mcpServers.{server_name}; rename it or remove it before installing the managed ICE entry"
            );
        }
        if existing == entry {
            return Ok((false, false));
        }
    }

    servers_obj.insert(server_name.to_string(), entry.clone());
    write_config(config_path, &config)?;
    Ok((true, false))
}

fn remove_managed_entry(config_path: &Path, server_name: &str) -> Result<(bool, bool)> {
    if !config_path.exists() {
        return Ok((false, false));
    }

    let (mut config, malformed) = read_config(config_path);
    if malformed {
        return Ok((false, true));
    }

    let changed = config
        .get_mut("mcpServers")
        .and_then(Value::as_object_mut)
        .map(|servers| {
            let managed = servers
                .get(server_name)
                .and_then(|value| value.get("_ice_managed"))
                .and_then(Value::as_bool)
                .unwrap_or(false);
            if managed {
                servers.remove(server_name);
                true
            } else {
                false
            }
        })
        .unwrap_or(false);

    if changed {
        write_config(config_path, &config)?;
    }

    Ok((changed, false))
}

fn has_ice_entry(config_path: &Path, server_name: &str) -> bool {
    let (config, malformed) = read_config(config_path);
    if malformed {
        return false;
    }
    config
        .get("mcpServers")
        .and_then(|value| value.get(server_name))
        .is_some()
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::tempdir;

    fn test_entry() -> Value {
        build_server_entry(
            &PathBuf::from("/tmp/ice"),
            &["--root".into(), "/tmp/organism".into(), "mcp".into()],
        )
    }

    #[test]
    fn upsert_creates_managed_entry() {
        let dir = tempdir().unwrap();
        let config = dir.path().join(".claude.json");

        let (changed, skipped) =
            upsert_code_entry(&config, DEFAULT_CLAUDE_SERVER_NAME, &test_entry()).unwrap();
        assert!(changed);
        assert!(!skipped);

        let written: Value = serde_json::from_str(&fs::read_to_string(&config).unwrap()).unwrap();
        assert!(
            written["mcpServers"][DEFAULT_CLAUDE_SERVER_NAME]["_ice_managed"]
                .as_bool()
                .unwrap()
        );
    }

    #[test]
    fn upsert_is_idempotent_for_same_managed_entry() {
        let dir = tempdir().unwrap();
        let config = dir.path().join(".claude.json");

        let first = upsert_code_entry(&config, DEFAULT_CLAUDE_SERVER_NAME, &test_entry()).unwrap();
        let second = upsert_code_entry(&config, DEFAULT_CLAUDE_SERVER_NAME, &test_entry()).unwrap();
        assert_eq!(first, (true, false));
        assert_eq!(second, (false, false));
    }

    #[test]
    fn upsert_preserves_other_servers() {
        let dir = tempdir().unwrap();
        let config = dir.path().join(".claude.json");
        let initial = json!({
            "mcpServers": {
                "other": { "command": "other", "args": [] }
            }
        });
        fs::write(&config, serde_json::to_string_pretty(&initial).unwrap()).unwrap();

        upsert_code_entry(&config, DEFAULT_CLAUDE_SERVER_NAME, &test_entry()).unwrap();

        let written: Value = serde_json::from_str(&fs::read_to_string(&config).unwrap()).unwrap();
        assert_eq!(
            written["mcpServers"]["other"]["command"].as_str(),
            Some("other")
        );
        assert!(written["mcpServers"][DEFAULT_CLAUDE_SERVER_NAME].is_object());
    }

    #[test]
    fn upsert_rejects_unmanaged_collision() {
        let dir = tempdir().unwrap();
        let config = dir.path().join(".claude.json");
        let initial = json!({
            "mcpServers": {
                "ice-shared-continuity-kernel": { "command": "other", "args": [] }
            }
        });
        fs::write(&config, serde_json::to_string_pretty(&initial).unwrap()).unwrap();

        let err =
            upsert_code_entry(&config, DEFAULT_CLAUDE_SERVER_NAME, &test_entry()).unwrap_err();
        assert!(
            err.to_string()
                .contains("already contains unmanaged mcpServers.ice-shared-continuity-kernel")
        );
    }

    #[test]
    fn remove_only_removes_managed_entry() {
        let dir = tempdir().unwrap();
        let config = dir.path().join(".claude.json");
        let initial = json!({
            "mcpServers": {
                "ice-shared-continuity-kernel": {
                    "command": "/tmp/ice",
                    "args": [],
                    "_ice_managed": true
                },
                "other": { "command": "other", "args": [] }
            }
        });
        fs::write(&config, serde_json::to_string_pretty(&initial).unwrap()).unwrap();

        let (changed, skipped) = remove_managed_entry(&config, DEFAULT_CLAUDE_SERVER_NAME).unwrap();
        assert!(changed);
        assert!(!skipped);

        let written: Value = serde_json::from_str(&fs::read_to_string(&config).unwrap()).unwrap();
        assert!(
            written["mcpServers"]
                .get(DEFAULT_CLAUDE_SERVER_NAME)
                .is_none()
        );
        assert_eq!(
            written["mcpServers"]["other"]["command"].as_str(),
            Some("other")
        );
    }

    #[test]
    fn malformed_config_is_skipped_without_overwrite() {
        let dir = tempdir().unwrap();
        let config = dir.path().join(".claude.json");
        fs::write(&config, "not-json").unwrap();

        let (changed, skipped) =
            upsert_code_entry(&config, DEFAULT_CLAUDE_SERVER_NAME, &test_entry()).unwrap();
        assert!(!changed);
        assert!(skipped);
        assert_eq!(fs::read_to_string(&config).unwrap(), "not-json");
    }
}

use std::env;
use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use serde::Serialize;

use crate::config::EngineConfig;

pub const DEFAULT_CODEX_GLOBAL_SERVER_NAME: &str = "adhd_machine";
pub const DEFAULT_CODEX_MACHINE_ROOT_DIR: &str = "organisms/ice";

const MANAGED_BLOCK_PREFIX: &str = "# BEGIN ICE MANAGED MCP SERVER ";
const MANAGED_BLOCK_SUFFIX: &str = "# END ICE MANAGED MCP SERVER ";

#[derive(Debug, Clone)]
pub struct CodexGlobalInstallRequest {
    pub codex_home: Option<PathBuf>,
    pub config_path: Option<PathBuf>,
    pub machine_root: Option<PathBuf>,
    pub server_name: String,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct CodexGlobalInstallResult {
    pub changed: bool,
    pub codex_home: String,
    pub config_path: String,
    pub machine_root: String,
    pub server_name: String,
    pub command: String,
    pub args: Vec<String>,
    pub restart_required: bool,
}

pub fn install_global_mcp(request: CodexGlobalInstallRequest) -> Result<CodexGlobalInstallResult> {
    validate_server_name(&request.server_name)?;

    let config_path = request
        .config_path
        .as_ref()
        .map(resolve_absolute_path)
        .transpose()?;
    let codex_home = resolve_codex_home(request.codex_home.as_ref(), config_path.as_deref())?;
    let config_path = config_path.unwrap_or_else(|| codex_home.join("config.toml"));
    let machine_root = request
        .machine_root
        .as_ref()
        .map(resolve_absolute_path)
        .transpose()?
        .unwrap_or_else(|| codex_home.join(DEFAULT_CODEX_MACHINE_ROOT_DIR));
    let manifest_path = PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("Cargo.toml");
    let command = find_executable_on_path("cargo").unwrap_or_else(|| PathBuf::from("cargo"));
    let args = vec![
        "run".to_string(),
        "--quiet".to_string(),
        "--manifest-path".to_string(),
        manifest_path.display().to_string(),
        "--".to_string(),
        "--root".to_string(),
        machine_root.display().to_string(),
        "mcp".to_string(),
    ];

    fs::create_dir_all(&codex_home)
        .with_context(|| format!("creating Codex home {}", codex_home.display()))?;
    if let Some(parent) = config_path.parent() {
        fs::create_dir_all(parent)
            .with_context(|| format!("creating config parent {}", parent.display()))?;
    }
    EngineConfig::with_root(&machine_root)
        .ensure_dirs()
        .with_context(|| format!("ensuring machine root {}", machine_root.display()))?;

    let existing = if config_path.exists() {
        fs::read_to_string(&config_path)
            .with_context(|| format!("reading Codex config {}", config_path.display()))?
    } else {
        String::new()
    };
    let block = render_managed_mcp_block(&request.server_name, &command, &args)?;
    let update = upsert_managed_mcp_block(&existing, &request.server_name, &block)?;
    if update.changed {
        fs::write(&config_path, update.content)
            .with_context(|| format!("writing Codex config {}", config_path.display()))?;
    }

    Ok(CodexGlobalInstallResult {
        changed: update.changed,
        codex_home: codex_home.display().to_string(),
        config_path: config_path.display().to_string(),
        machine_root: machine_root.display().to_string(),
        server_name: request.server_name,
        command: command.display().to_string(),
        args,
        restart_required: true,
    })
}

#[derive(Debug)]
struct ManagedBlockUpdate {
    content: String,
    changed: bool,
}

fn resolve_codex_home(
    requested_home: Option<&PathBuf>,
    config_path: Option<&Path>,
) -> Result<PathBuf> {
    if let Some(home) = requested_home {
        return resolve_absolute_path(home);
    }
    if let Some(config_path) = config_path {
        if let Some(parent) = config_path.parent() {
            return Ok(parent.to_path_buf());
        }
    }
    if let Some(value) = env::var_os("CODEX_HOME") {
        let path = PathBuf::from(value);
        if !path.as_os_str().is_empty() {
            return resolve_absolute_path(&path);
        }
    }
    let home =
        env::var_os("HOME").context("HOME or CODEX_HOME must be set to resolve Codex home")?;
    Ok(PathBuf::from(home).join(".codex"))
}

fn resolve_absolute_path(path: impl AsRef<Path>) -> Result<PathBuf> {
    let path = path.as_ref();
    if path.is_absolute() {
        return Ok(path.to_path_buf());
    }
    Ok(env::current_dir()
        .context("resolving current working directory")?
        .join(path))
}

fn validate_server_name(server_name: &str) -> Result<()> {
    if server_name.is_empty()
        || !server_name
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '-')
    {
        anyhow::bail!(
            "server name must contain only ASCII letters, digits, underscores, or hyphens"
        );
    }
    Ok(())
}

fn find_executable_on_path(name: &str) -> Option<PathBuf> {
    let path = env::var_os("PATH")?;
    env::split_paths(&path)
        .map(|dir| dir.join(name))
        .find(|candidate| candidate.is_file())
}

fn render_managed_mcp_block(server_name: &str, command: &Path, args: &[String]) -> Result<String> {
    let rendered_args = args
        .iter()
        .map(|value| toml_string(value))
        .collect::<Result<Vec<_>>>()?
        .join(", ");
    Ok(format!(
        "{}{}\n[mcp_servers.{}]\ncommand = {}\nargs = [{}]\n{}{}\n",
        MANAGED_BLOCK_PREFIX,
        server_name,
        server_name,
        toml_string(&command.display().to_string())?,
        rendered_args,
        MANAGED_BLOCK_SUFFIX,
        server_name
    ))
}

fn toml_string(value: &str) -> Result<String> {
    serde_json::to_string(value).context("encoding TOML string")
}

fn upsert_managed_mcp_block(
    existing: &str,
    server_name: &str,
    block: &str,
) -> Result<ManagedBlockUpdate> {
    let begin_marker = managed_begin_marker(server_name);
    let end_marker = managed_end_marker(server_name);
    let managed_range = managed_block_range(existing, &begin_marker, &end_marker)?;
    let unmanaged = match managed_range {
        Some((start, end)) => {
            let mut stripped = String::with_capacity(existing.len() - (end - start));
            stripped.push_str(&existing[..start]);
            stripped.push_str(&existing[end..]);
            stripped
        }
        None => existing.to_string(),
    };
    ensure_no_unmanaged_server_block(&unmanaged, server_name)?;
    let normalized_block = normalize_managed_block(block);
    let next = match managed_range {
        Some((start, end)) => {
            let mut updated = String::with_capacity(existing.len() + normalized_block.len());
            updated.push_str(&existing[..start]);
            updated.push_str(&normalized_block);
            updated.push_str(&existing[end..]);
            updated
        }
        None => append_managed_block(existing, &normalized_block),
    };
    Ok(ManagedBlockUpdate {
        changed: next != existing,
        content: next,
    })
}

fn managed_begin_marker(server_name: &str) -> String {
    format!("{MANAGED_BLOCK_PREFIX}{server_name}")
}

fn managed_end_marker(server_name: &str) -> String {
    format!("{MANAGED_BLOCK_SUFFIX}{server_name}")
}

fn managed_block_range(
    existing: &str,
    begin_marker: &str,
    end_marker: &str,
) -> Result<Option<(usize, usize)>> {
    let begin = existing.find(begin_marker);
    let end = existing.find(end_marker);
    match (begin, end) {
        (None, None) => Ok(None),
        (Some(_), None) | (None, Some(_)) => anyhow::bail!(
            "Codex config contains an incomplete managed ICE MCP block; repair or remove it first"
        ),
        (Some(begin), Some(end)) if end < begin => {
            anyhow::bail!("Codex config contains a malformed managed ICE MCP block ordering")
        }
        (Some(begin), Some(end)) => {
            let end_line = existing[end..]
                .find('\n')
                .map(|offset| end + offset + 1)
                .unwrap_or(existing.len());
            Ok(Some((begin, end_line)))
        }
    }
}

fn ensure_no_unmanaged_server_block(existing: &str, server_name: &str) -> Result<()> {
    let header = format!("[mcp_servers.{server_name}]");
    if existing.lines().any(|line| line.trim() == header) {
        anyhow::bail!(
            "Codex config already contains unmanaged {header}; rename it or remove it before installing the managed ICE block"
        );
    }
    Ok(())
}

fn normalize_managed_block(block: &str) -> String {
    let trimmed = block.trim_matches('\n');
    format!("{trimmed}\n")
}

fn append_managed_block(existing: &str, block: &str) -> String {
    if existing.trim().is_empty() {
        return block.to_string();
    }
    let trimmed = existing.trim_end_matches('\n');
    format!("{trimmed}\n\n{block}")
}

#[cfg(test)]
mod tests {
    use super::{
        CodexGlobalInstallRequest, DEFAULT_CODEX_GLOBAL_SERVER_NAME, append_managed_block,
        install_global_mcp, managed_begin_marker, managed_end_marker, render_managed_mcp_block,
        upsert_managed_mcp_block,
    };
    use tempfile::tempdir;

    #[test]
    fn append_managed_block_separates_existing_config_cleanly() {
        let appended = append_managed_block("model = \"gpt-5.4\"\n", "# block\n");
        assert_eq!(appended, "model = \"gpt-5.4\"\n\n# block\n");
    }

    #[test]
    fn managed_block_upsert_is_idempotent() {
        let block = render_managed_mcp_block(
            DEFAULT_CODEX_GLOBAL_SERVER_NAME,
            "/opt/homebrew/bin/cargo".as_ref(),
            &[
                "run".to_string(),
                "--quiet".to_string(),
                "--manifest-path".to_string(),
                "/tmp/adhd/Cargo.toml".to_string(),
                "--".to_string(),
                "--root".to_string(),
                "/tmp/.codex/organisms/ice".to_string(),
                "mcp".to_string(),
            ],
        )
        .expect("render managed block");
        let first = upsert_managed_mcp_block("model = \"gpt-5.4\"\n", "adhd_machine", &block)
            .expect("append managed block");
        assert!(first.changed);
        let second = upsert_managed_mcp_block(&first.content, "adhd_machine", &block)
            .expect("replace managed block idempotently");
        assert!(!second.changed);
        assert_eq!(first.content, second.content);
        assert!(
            second
                .content
                .contains(&managed_begin_marker("adhd_machine"))
        );
        assert!(second.content.contains(&managed_end_marker("adhd_machine")));
    }

    #[test]
    fn managed_block_upsert_rejects_unmanaged_duplicate_server() {
        let block = render_managed_mcp_block(
            DEFAULT_CODEX_GLOBAL_SERVER_NAME,
            "/opt/homebrew/bin/cargo".as_ref(),
            &[
                "run".to_string(),
                "--quiet".to_string(),
                "--manifest-path".to_string(),
                "/tmp/adhd/Cargo.toml".to_string(),
                "--".to_string(),
                "--root".to_string(),
                "/tmp/.codex/organisms/ice".to_string(),
                "mcp".to_string(),
            ],
        )
        .expect("render managed block");
        let err = upsert_managed_mcp_block(
            "[mcp_servers.adhd_machine]\ncommand = \"cargo\"\nargs = [\"run\"]\n",
            "adhd_machine",
            &block,
        )
        .expect_err("reject unmanaged duplicate");
        assert!(err.to_string().contains("unmanaged"));
    }

    #[test]
    fn install_global_mcp_creates_machine_root_and_config() {
        let dir = tempdir().expect("create temp dir");
        let codex_home = dir.path().join(".codex");
        let machine_root = dir.path().join("brain");
        let config_path = codex_home.join("config.toml");

        let result = install_global_mcp(CodexGlobalInstallRequest {
            codex_home: Some(codex_home.clone()),
            config_path: Some(config_path.clone()),
            machine_root: Some(machine_root.clone()),
            server_name: DEFAULT_CODEX_GLOBAL_SERVER_NAME.to_string(),
        })
        .expect("install global mcp");

        assert!(result.changed);
        assert!(config_path.exists());
        assert!(machine_root.join("data").exists());
    }
}

